import{_ as r,C as c,o as a,c as d,a3 as o,b as i,w as t,a as l,E as s,a4 as u}from"./chunks/framework.aYYe0dfI.js";const x=JSON.parse('{"title":"Module agent","description":"The agent module implements the core agent loop that explores a codebase through tool calls and produces guide documents under a configured output directory. It manages the conversation with an LLM, caches responses to avoid redundant tool calls, and handles serialization and deserialization of completion data. Internally, it coordinates tasks like hashing message history, generating cache keys, and iterating over tool call results until the agent terminates or reaches a maximum number of turns.","frontmatter":{"title":"Module agent","description":"The agent module implements the core agent loop that explores a codebase through tool calls and produces guide documents under a configured output directory. It manages the conversation with an LLM, caches responses to avoid redundant tool calls, and handles serialization and deserialization of completion data. Internally, it coordinates tasks like hashing message history, generating cache keys, and iterating over tool call results until the agent terminates or reaches a maximum number of turns.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/agent/index.md","filePath":"en/clore/modules/agent/index.md"}'),h={name:"clore/modules/agent/index.md"};function g(p,e,m,f,_,y){const n=c("Mermaid");return a(),d("div",null,[e[1]||(e[1]=o('<h1 id="module-agent" tabindex="-1">Module <code>agent</code> <a class="header-anchor" href="#module-agent" aria-label="Permalink to &quot;Module `agent`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>agent</code> module implements the core agent loop that explores a codebase through tool calls and produces guide documents under a configured output directory. It manages the conversation with an LLM, caches responses to avoid redundant tool calls, and handles serialization and deserialization of completion data. Internally, it coordinates tasks like hashing message history, generating cache keys, and iterating over tool call results until the agent terminates or reaches a maximum number of turns.</p><p>The public-facing interface consists of two entry points: <code>clore::agent::run_agent</code> for synchronous execution and <code>clore::agent::run_agent_async</code> for asynchronous execution on a caller-provided event loop. Both functions accept parameters that define concurrency limits, output paths, and the LLM model. On success, they return a count of generated guides; on failure, they return a descriptive <code>AgentError</code>. The module also exposes the <code>AgentError</code> struct, which carries a human-readable message.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><a href="./../extract/"><code>extract</code></a></li><li><a href="./../generate/"><code>generate</code></a></li><li><a href="./../network/"><code>network</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',7)),(a(),i(u,null,{default:t(()=>[s(n,{id:"mermaid-50",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22agent%22%5D%0A%20%20%20%20I0%5B%22config%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22extract%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22generate%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A%20%20%20%20I3%5B%22network%22%5D%0A%20%20%20%20I3%20--%3E%20M0%0A%20%20%20%20I4%5B%22support%22%5D%0A%20%20%20%20I4%20--%3E%20M0%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-agent-agenterror" tabindex="-1"><code>clore::agent::AgentError</code> <a class="header-anchor" href="#clore-agent-agenterror" aria-label="Permalink to &quot;`clore::agent::AgentError`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:21</code></p><p>Definition: <code>agent/agent.cppm:21</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The struct <code>clore::agent::AgentError</code> is a simple error type that holds a single <code>std::string message</code> member. Its purpose is to encapsulate a human-readable error description for operations within the <code>clore::agent</code> module. The class relies on compiler-generated special member functions, providing default construction, copy, move, and assignment semantics for the <code>message</code> field. The only invariant is that <code>message</code> contains a valid string; no non-trivial or complex state is maintained, making the implementation transparent and minimal.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>message should be a valid, non-empty string when describing an error</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li>message</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used as a return type or thrown as an exception to indicate agent-related errors</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-agent-run-agent" tabindex="-1"><code>clore::agent::run_agent</code> <a class="header-anchor" href="#clore-agent-run-agent" aria-label="Permalink to &quot;`clore::agent::run_agent`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:27</code></p><p>Definition: <code>agent/agent.cppm:524</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The function creates a <code>kota::event_loop</code> and delegates to <code>run_agent_async</code> to obtain a <code>task</code>. It schedules the task on the loop and then synchronously runs the loop until all pending work completes. Once the loop finishes, it retrieves the task result and either returns the contained <code>std::size_t</code> on success or wraps the error into <code>std::unexpected</code> as an <code>AgentError</code>.</p><p>Internally, <code>run_agent</code> acts as a thin synchronous wrapper around the asynchronous <code>run_agent_async</code>; all algorithm and I/O logic resides in that inner function. The only dependencies are on <code>kota::event_loop</code> for scheduling and execution, and on the <code>run_agent_async</code> function which implements the actual agent loop, LLM interaction, tool call dispatch, caching, and guide generation.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>runs an event loop which may perform I/O and other side effects</li><li>schedules and executes the asynchronous agent task that explores the codebase and writes guide documents</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>config</code> parameter of type <code>const config::TaskConfig&amp;</code></li><li><code>model</code> parameter of type <code>const extract::ProjectModel&amp;</code></li><li><code>llm_model</code> parameter of type <code>std::string_view</code></li><li><code>output_root</code> parameter of type <code>std::string</code></li><li><code>loop</code> local variable of type <code>kota::event_loop</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>loop</code> local variable (event loop state)</li><li><code>result</code> local variable (holds task result)</li><li>potentially writes guide files under <code>output_root</code> via the async task</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>synchronous entry point for running the agent</li><li>callers use it to execute the agent loop and obtain a result</li><li>typically called with a configuration, project model, LLM model name, and output directory</li></ul><h3 id="clore-agent-run-agent-async" tabindex="-1"><code>clore::agent::run_agent_async</code> <a class="header-anchor" href="#clore-agent-run-agent-async" aria-label="Permalink to &quot;`clore::agent::run_agent_async`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:34</code></p><p>Definition: <code>agent/agent.cppm:507</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The function begins by attempting to load a cache index from the workspace root specified in <code>config</code> via <code>clore::generate::cache::load_cache_index</code>. On success, the result is moved into a local <code>clore::generate::cache::CacheIndex</code> variable and a success message is logged; on failure, a warning is logged using the error’s <code>message</code> field. The function then suspends itself and <code>co_awaits</code> <code>clore::agent::(anonymous namespace)::run_agent_loop</code>, forwarding its own <code>config</code>, <code>model</code>, <code>llm_model</code>, <code>output_root</code>, <code>loop</code>, and the freshly‑loaded <code>cache_index</code>. This design ensures that cache state is established (or gracefully degraded) before the main loop begins, and that the coroutine integrates cleanly with the provided <code>kota::event_loop</code>. Dependencies include <code>kota::task</code>, the internal agent loop, and the <code>clore::generate::cache</code> module’s index types and loader.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>reads cache index from disk via <code>clore::generate::cache::load_cache_index</code></li><li>logs info or warn messages via <code>logging::info</code> and <code>logging::warn</code></li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>config.workspace_root</code> (string path for cache file)</li><li><code>model</code> (<code>extract::ProjectModel</code>)</li><li><code>llm_model</code> (string)</li><li><code>output_root</code> (string)</li><li><code>loop</code> (<code>kota::event_loop</code>)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>local variable <code>cache_index</code> (<code>clore::generate::cache::CacheIndex</code>) via move</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>callers must schedule the returned task on the event loop and run it</li><li>used to start an asynchronous agent loop with cache loading</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>agent</code> module orchestrates the top-level agent loop that explores a codebase and produces guide documents. It imports from five sibling modules — <code>config</code>, <code>extract</code>, <code>generate</code>, <code>network</code>, and <code>support</code> — along with <code>std</code>. Public entry points are <code>run_agent</code> and <code>run_agent_async</code>. Internally, the module is decomposed into an anonymous namespace containing the core agent loop (<code>run_agent_loop</code>), helper functions for caching (<code>hash_messages</code>, <code>make_agent_cache_key</code>, <code>serialize_completion_response</code>, <code>deserialize_completion_response</code>), tool call execution (<code>run_tool_call</code>), and guide discovery (<code>list_existing_guide_filenames</code>). A <code>ToolCallResult</code> struct and an <code>AgentError</code> type encapsulate internal results and failures. The implementation structure separates the synchronous synchronous from the asynchronous entry point, with the latter expecting a caller-provided event loop and relying on the <code>network</code> module for LLM communication and <code>support</code> for file I/O and path handling.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../extract/">Module extract</a></li><li><a href="./../generate/">Module generate</a></li><li><a href="./../network/">Module network</a></li><li><a href="./../support/">Module support</a></li></ul>',44))])}const k=r(h,[["render",g]]);export{x as __pageData,k as default};
